<script setup>import{ref,nextTick}from'vue';const p=defineProps({title:String,size:String,modal:Boolean,open:Boolean,closeButton:{type:Boolean,default:true},closeOnEscape:{type:Boolean,default:true}});const el=ref(),shown=ref(p.open);const id=p.title.toLowerCase().replace(/\W/g,'-');async function show(){shown.value=true;await nextTick();p.modal?el.value.showModal():el.value.show()}function close(){el.value.close();shown.value=false}function cancel(e){if(!p.closeOnEscape)e.preventDefault()}</script><template><section class="dialog-demo"><strong>{{p.modal?'Modal':p.title}}</strong><button v-if="!shown" @click="show">Open dialog</button><dialog ref="el" :open="shown&&!p.modal" :class="['kumo-dialog',p.size]" :aria-labelledby="id" :aria-describedby="id+'-desc'" :aria-modal="p.modal||undefined" @cancel="cancel" @close="shown=false"><h2 :id="id" class="dialog-title">{{p.title}}</h2><p :id="id+'-desc'" class="dialog-description">Dialog content and keyboard behavior preview.</p><button v-if="p.closeButton" class="dialog-close" aria-label="Close" @click="close">×</button><div class="dialog-actions"><button @click="close">Cancel</button><button class="primary" @click="close">Confirm</button></div></dialog></section></template>